"""Модуль для автоматического сбора параметров номенклатурных листовтопографических карт для Тверской области из открытых источников"""import jsonimport osimport reimport loggingimport aiohttpimport asynciofrom typing import Dict, List, Optional, Tuplefrom datetime import datetimelogger = logging.getLogger(__name__)# Путь к файлу кэшаCACHE_FILE = "data/zone_params_cache.json"class ZoneParamsCollector:    """    Класс для сбора параметров зон и номенклатурных листов    из открытых источников (EPSG.io, georepository.com)    """        # Базовые параметры для зон СК-42 (известные константы)    ZONES_BASE = {        '5': {            'epsg': 28405,            'name': 'Зона 5',            'central_meridian': 27,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0,            'sheets': []        },        '6': {            'epsg': 28406,            'name': 'Зона 6',            'central_meridian': 33,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0,            'sheets': []        },        '7': {            'epsg': 28407,            'name': 'Зона 7',            'central_meridian': 39,            'false_easting': 500000,            'false_northing': 0,            'scale_factor': 1.0,            'latitude_of_origin': 0,            'sheets': []        }    }        # Номенклатурные листы для Тверской области    # Данные основаны на стандартной разграфке карт масштаба 1:100 000    TVER_SHEETS = [        # Зона 5 (западная часть Тверской области)        {'sheet': 'O35-21', 'zone': '5', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 30.0, 'lon_max': 31.0},        {'sheet': 'O35-22', 'zone': '5', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 31.0, 'lon_max': 32.0},        {'sheet': 'O35-23', 'zone': '5', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 32.0, 'lon_max': 33.0},        {'sheet': 'O35-24', 'zone': '5', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 33.0, 'lon_max': 34.0},        {'sheet': 'O35-25', 'zone': '5', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 34.0, 'lon_max': 35.0},        {'sheet': 'O35-26', 'zone': '5', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 35.0, 'lon_max': 36.0},        {'sheet': 'O35-27', 'zone': '5', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 36.0, 'lon_max': 37.0},        {'sheet': 'O35-28', 'zone': '5', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 37.0, 'lon_max': 38.0},                # Зона 6 (центральная часть Тверской области)        {'sheet': 'O36-141', 'zone': '6', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 33.0, 'lon_max': 34.0},        {'sheet': 'O36-142', 'zone': '6', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 34.0, 'lon_max': 35.0},        {'sheet': 'O36-143', 'zone': '6', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 35.0, 'lon_max': 36.0},        {'sheet': 'O36-144', 'zone': '6', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 36.0, 'lon_max': 37.0},        {'sheet': 'O36-145', 'zone': '6', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 37.0, 'lon_max': 38.0},        {'sheet': 'N36-017', 'zone': '6', 'lat_min': 56.4, 'lat_max': 56.8, 'lon_min': 33.0, 'lon_max': 34.0},        {'sheet': 'N36-018', 'zone': '6', 'lat_min': 56.4, 'lat_max': 56.8, 'lon_min': 34.0, 'lon_max': 35.0},        {'sheet': 'N36-019', 'zone': '6', 'lat_min': 56.4, 'lat_max': 56.8, 'lon_min': 35.0, 'lon_max': 36.0},        {'sheet': 'N36-020', 'zone': '6', 'lat_min': 56.4, 'lat_max': 56.8, 'lon_min': 36.0, 'lon_max': 37.0},        {'sheet': 'N36-021', 'zone': '6', 'lat_min': 56.4, 'lat_max': 56.8, 'lon_min': 37.0, 'lon_max': 38.0},        {'sheet': 'P36-105', 'zone': '6', 'lat_min': 55.6, 'lat_max': 56.0, 'lon_min': 33.0, 'lon_max': 34.0},        {'sheet': 'P36-106', 'zone': '6', 'lat_min': 55.6, 'lat_max': 56.0, 'lon_min': 34.0, 'lon_max': 35.0},        {'sheet': 'P36-107', 'zone': '6', 'lat_min': 55.6, 'lat_max': 56.0, 'lon_min': 35.0, 'lon_max': 36.0},        {'sheet': 'P36-108', 'zone': '6', 'lat_min': 55.6, 'lat_max': 56.0, 'lon_min': 36.0, 'lon_max': 37.0},        {'sheet': 'P36-109', 'zone': '6', 'lat_min': 55.6, 'lat_max': 56.0, 'lon_min': 37.0, 'lon_max': 38.0},                # Зона 7 (восточная часть Тверской области)        {'sheet': 'O37-105', 'zone': '7', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 36.0, 'lon_max': 37.0},        {'sheet': 'O37-106', 'zone': '7', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 37.0, 'lon_max': 38.0},        {'sheet': 'O37-107', 'zone': '7', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 38.0, 'lon_max': 39.0},        {'sheet': 'O37-108', 'zone': '7', 'lat_min': 56.0, 'lat_max': 56.4, 'lon_min': 39.0, 'lon_max': 40.0},        {'sheet': 'N37-082', 'zone': '7', 'lat_min': 56.4, 'lat_max': 56.8, 'lon_min': 36.0, 'lon_max': 37.0},        {'sheet': 'N37-083', 'zone': '7', 'lat_min': 56.4, 'lat_max': 56.8, 'lon_min': 37.0, 'lon_max': 38.0},        {'sheet': 'N37-084', 'zone': '7', 'lat_min': 56.4, 'lat_max': 56.8, 'lon_min': 38.0, 'lon_max': 39.0},        {'sheet': 'N37-085', 'zone': '7', 'lat_min': 56.4, 'lat_max': 56.8, 'lon_min': 39.0, 'lon_max': 40.0},        {'sheet': 'P37-122', 'zone': '7', 'lat_min': 55.6, 'lat_max': 56.0, 'lon_min': 36.0, 'lon_max': 37.0},        {'sheet': 'P37-123', 'zone': '7', 'lat_min': 55.6, 'lat_max': 56.0, 'lon_min': 37.0, 'lon_max': 38.0},        {'sheet': 'P37-124', 'zone': '7', 'lat_min': 55.6, 'lat_max': 56.0, 'lon_min': 38.0, 'lon_max': 39.0},        {'sheet': 'P37-125', 'zone': '7', 'lat_min': 55.6, 'lat_max': 56.0, 'lon_min': 39.0, 'lon_max': 40.0},    ]        def __init__(self):        self.cache = self._load_cache()        self.session = None        def _load_cache(self) -> Dict:        """Загружает кэш параметров из файла"""        if os.path.exists(CACHE_FILE):            try:                with open(CACHE_FILE, 'r', encoding='utf-8') as f:                    return json.load(f)            except Exception as e:                logger.error(f"Ошибка загрузки кэша: {e}")        return {}        def _save_cache(self):        """Сохраняет кэш параметров в файл"""        os.makedirs(os.path.dirname(CACHE_FILE), exist_ok=True)        try:            with open(CACHE_FILE, 'w', encoding='utf-8') as f:                json.dump(self.cache, f, ensure_ascii=False, indent=2)            logger.info(f"? Кэш сохранен: {CACHE_FILE}")        except Exception as e:            logger.error(f"Ошибка сохранения кэша: {e}")        async def _get_session(self) -> aiohttp.ClientSession:        """Возвращает сессию aiohttp"""        if self.session is None or self.session.closed:            self.session = aiohttp.ClientSession()        return self.session        async def fetch_epsg_params(self, epsg_code: int) -> Optional[Dict]:        """        Получает параметры проекции из EPSG.io        """        cache_key = f"epsg_{epsg_code}"        if cache_key in self.cache:            logger.info(f"?? Используем кэш для EPSG:{epsg_code}")            return self.cache[cache_key]                try:            session = await self._get_session()            url = f"https://epsg.io/{epsg_code}.json"                        async with session.get(url, timeout=30) as response:                if response.status == 200:                    data = await response.json()                    params = self._parse_epsg_response(data)                    if params:                        self.cache[cache_key] = params                        self._save_cache()                        logger.info(f"? Загружены параметры EPSG:{epsg_code}")                        return params                else:                    logger.warning(f"?? EPSG.io вернул статус {response.status}")        except Exception as e:            logger.error(f"Ошибка запроса к EPSG.io: {e}")                # Возвращаем базовые параметры, если API недоступен        return self._get_base_epsg_params(epsg_code)        def _parse_epsg_response(self, data: Dict) -> Dict:        """Парсит ответ EPSG.io"""        try:            params = {                'epsg': data.get('code'),                'name': data.get('name'),                'proj4': data.get('proj4'),                'wkt': data.get('wkt')            }                        # Извлекаем центральный меридиан из proj4            proj4 = data.get('proj4', '')            cm_match = re.search(r'\+lon_0=([\d\.]+)', proj4)            if cm_match:                params['central_meridian'] = float(cm_match.group(1))                        return params        except Exception as e:            logger.error(f"Ошибка парсинга EPSG ответа: {e}")            return None        def _get_base_epsg_params(self, epsg_code: int) -> Dict:        """Возвращает базовые параметры для EPSG кода"""        base_params = {            28405: {'central_meridian': 27, 'name': 'СК-42 / zone 5', 'proj4': '+proj=tmerc +lat_0=0 +lon_0=27 +k=1 +x_0=500000 +y_0=0 +ellps=krass +towgs84=24,-123,-94,0,0,0,0 +units=m +no_defs'},            28406: {'central_meridian': 33, 'name': 'СК-42 / zone 6', 'proj4': '+proj=tmerc +lat_0=0 +lon_0=33 +k=1 +x_0=500000 +y_0=0 +ellps=krass +towgs84=24,-123,-94,0,0,0,0 +units=m +no_defs'},            28407: {'central_meridian': 39, 'name': 'СК-42 / zone 7', 'proj4': '+proj=tmerc +lat_0=0 +lon_0=39 +k=1 +x_0=500000 +y_0=0 +ellps=krass +towgs84=24,-123,-94,0,0,0,0 +units=m +no_defs'},        }        return base_params.get(epsg_code, {'central_meridian': 33, 'name': 'Unknown'})        async def collect_all_params(self) -> Dict:        """        Собирает параметры для всех зон и номенклатурных листов        """        logger.info("?? Начало сбора параметров для всех зон")                result = {            'zones': {},            'sheets': {},            'collected_at': datetime.now().isoformat(),            'source': 'EPSG.io + local database'        }                # Собираем параметры для каждой зоны        for zone_num, zone_base in self.ZONES_BASE.items():            epsg = zone_base['epsg']                        # Получаем параметры из EPSG.io            epsg_params = await self.fetch_epsg_params(epsg)                        zone_params = {                'number': zone_num,                'epsg': epsg,                'name': zone_base['name'],                'central_meridian': epsg_params.get('central_meridian', zone_base['central_meridian']) if epsg_params else zone_base['central_meridian'],                'false_easting': zone_base['false_easting'],                'false_northing': zone_base['false_northing'],                'scale_factor': zone_base['scale_factor'],                'latitude_of_origin': zone_base['latitude_of_origin']            }                        result['zones'][zone_num] = zone_params                        # Добавляем информацию о номенклатурных листах для этой зоны            for sheet in self.TVER_SHEETS:                if sheet['zone'] == zone_num:                    result['sheets'][sheet['sheet']] = {                        'zone': sheet['zone'],                        'epsg': epsg,                        'central_meridian': zone_params['central_meridian'],                        'lat_min': sheet['lat_min'],                        'lat_max': sheet['lat_max'],                        'lon_min': sheet['lon_min'],                        'lon_max': sheet['lon_max']                    }                logger.info(f"? Собрано {len(result['zones'])} зон и {len(result['sheets'])} номенклатурных листов")                return result        def get_zone_by_coords(self, x: float, y: float, zone_number: Optional[str] = None) -> Optional[Dict]:        """        Определяет зону по координатам x,y        """        # Если зона указана явно, используем её        if zone_number and zone_number in self.ZONES_BASE:            return self.ZONES_BASE[zone_number]                # Пробуем определить зону по значению y (восточная координата)        # В зональной системе первая цифра y указывает на зону        y_str = str(int(y))        if len(y_str) >= 7:            zone_digit = y_str[0]            if zone_digit in self.ZONES_BASE:                return self.ZONES_BASE[zone_digit]                # По умолчанию возвращаем зону 6 (центральная часть Тверской области)        return self.ZONES_BASE.get('6')        def get_sheet_by_name(self, sheet_name: str) -> Optional[Dict]:        """        Получает параметры номенклатурного листа по его названию        """        for sheet in self.TVER_SHEETS:            if sheet['sheet'].upper() == sheet_name.upper():                return sheet        return None        def get_sheet_by_coords(self, lat: float, lon: float) -> Optional[Dict]:        """        Определяет номенклатурный лист по географическим координатам        """        for sheet in self.TVER_SHEETS:            if (sheet['lat_min'] <= lat <= sheet['lat_max'] and                sheet['lon_min'] <= lon <= sheet['lon_max']):                return sheet        return None        def calculate_offsets(self, sheet: Dict, scale: int = 100000) -> Tuple[float, float]:        """        Вычисляет смещения X и Y для номенклатурного листа        """        # Для масштаба 1:100 000 размер листа 100?100 км        # Смещение вычисляется на основе координат углов листа        lat_center = (sheet['lat_min'] + sheet['lat_max']) / 2        lon_center = (sheet['lon_min'] + sheet['lon_max']) / 2                # Грубое преобразование градусов в метры        lat_meters = lat_center * 111000        lon_meters = lon_center * 85000                return lat_meters, lon_meters        async def close_session(self):        """Закрывает сессию aiohttp"""        if self.session and not self.session.closed:            await self.session.close()# Функция для быстрого получения параметровasync def get_zone_params(zone_number: str = None) -> Dict:    """    Быстрый доступ к параметрам зон    """    collector = ZoneParamsCollector()    result = collector.ZONES_BASE    await collector.close_session()    return result# Функция для определения зоны по координатамdef detect_zone_by_coords(x: float, y: float, zone_hint: str = None) -> Dict:    """    Определяет зону по координатам x,y    """    collector = ZoneParamsCollector()    return collector.get_zone_by_coords(x, y, zone_hint)# Функция для получения параметров номенклатурного листаdef get_sheet_params(sheet_name: str) -> Optional[Dict]:    """    Получает параметры номенклатурного листа    """    collector = ZoneParamsCollector()    return collector.get_sheet_by_name(sheet_name)